import{_ as n,c as a,o as e,a as l}from"./chunks/plugin-vue_export-helper.dqZ0aIgD.js";const m=JSON.parse('{"title":"Configuration","description":"Lynq operator configuration reference: controller runtime flags, concurrency knobs (node, hub, form), requeue intervals, and feature gates.","frontmatter":{"description":"Lynq operator configuration reference: controller runtime flags, concurrency knobs (node, hub, form), requeue intervals, and feature gates."},"headers":[],"relativePath":"configuration.md","filePath":"configuration.md","lastUpdated":1778724160000}'),r={name:"configuration.md"};function t(o,s,p,c,i,d){return e(),a("div",null,[...s[0]||(s[0]=[l(`<h1 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h1><p>This page covers the controller manager&#39;s runtime flags. For resource-level configuration (hub connection, form policies, templates), follow the links in each section.</p><h2 id="controller-flags" tabindex="-1">Controller Flags <a class="header-anchor" href="#controller-flags" aria-label="Permalink to &quot;Controller Flags&quot;">​</a></h2><p>Set in <code>config/manager/manager.yaml</code> under <code>spec.template.spec.containers[].args</code>:</p><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#85E89D;">args</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#6A737D;">  # Leader election</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#9ECBFF;">--leader-elect=true</span><span style="color:#6A737D;">                        # required in HA deployments</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;">  # Concurrency (tune for cluster scale)</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#9ECBFF;">--hub-concurrency=3</span><span style="color:#6A737D;">                        # concurrent hub syncs (default: 3)</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#9ECBFF;">--form-concurrency=5</span><span style="color:#6A737D;">                       # concurrent form reconciliations (default: 5)</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#9ECBFF;">--node-concurrency=10</span><span style="color:#6A737D;">                      # concurrent node reconciliations (default: 10)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;">  # Metrics and health</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#9ECBFF;">--metrics-bind-address=:8443</span><span style="color:#6A737D;">               # Prometheus scrape endpoint (0 = disabled)</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#9ECBFF;">--health-probe-bind-address=:8081</span><span style="color:#6A737D;">          # liveness/readiness probes</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#9ECBFF;">--metrics-secure=true</span><span style="color:#6A737D;">                      # serve metrics over HTTPS</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;">  # TLS (cert-manager provisions these automatically)</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#9ECBFF;">--webhook-cert-path=/tmp/k8s-webhook-server/serving-certs</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#9ECBFF;">--metrics-cert-path=/tmp/k8s-metrics-server/serving-certs</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;">  # Logging</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#9ECBFF;">--zap-log-level=info</span><span style="color:#6A737D;">                       # debug | info | error</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#9ECBFF;">--zap-encoder=json</span><span style="color:#6A737D;">                         # json | console</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#9ECBFF;">--zap-devel=false</span><span style="color:#6A737D;">                          # true enables development mode</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br></div></div><p><strong>Concurrency guidance:</strong></p><table tabindex="0"><thead><tr><th>Cluster scale</th><th>hub</th><th>form</th><th>node</th></tr></thead><tbody><tr><td>Small (&lt;50 nodes)</td><td>3</td><td>5</td><td>10</td></tr><tr><td>Medium (50–500)</td><td>5</td><td>8</td><td>20</td></tr><tr><td>Large (500+)</td><td>8</td><td>10</td><td>30</td></tr></tbody></table><p>For more tuning options, see <a href="./performance.html">Performance</a>.</p><h2 id="resource-limits" tabindex="-1">Resource Limits <a class="header-anchor" href="#resource-limits" aria-label="Permalink to &quot;Resource Limits&quot;">​</a></h2><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#85E89D;">resources</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">  requests</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">    cpu</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">200m</span></span>
<span class="line"><span style="color:#85E89D;">    memory</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">256Mi</span></span>
<span class="line"><span style="color:#85E89D;">  limits</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">    cpu</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">1000m</span></span>
<span class="line"><span style="color:#85E89D;">    memory</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">1Gi</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>These defaults suit clusters up to ~200 LynqNodes. For observed benchmarks, a sizing table, and a CPU/memory model, see <a href="./resource-sizing.html">Resource Sizing</a>.</p><h2 id="configuration-by-topic" tabindex="-1">Configuration by Topic <a class="header-anchor" href="#configuration-by-topic" aria-label="Permalink to &quot;Configuration by Topic&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Topic</th><th>Where to configure</th><th>Reference</th></tr></thead><tbody><tr><td>Database connection, sync interval, column mappings</td><td><code>LynqHub</code> spec</td><td><a href="./datasource.html">Datasource</a></td></tr><tr><td>Resource blueprints, rollout settings</td><td><code>LynqForm</code> spec</td><td><a href="./templates.html">Templates</a></td></tr><tr><td>CreationPolicy, DeletionPolicy, ConflictPolicy, PatchStrategy</td><td>Per-resource in <code>LynqForm</code></td><td><a href="./policies.html">Policies</a></td></tr><tr><td>Prometheus metrics, alerting</td><td>Operator flags + Prometheus config</td><td><a href="./monitoring.html">Monitoring</a></td></tr><tr><td>RBAC, network policies, credentials</td><td>Cluster config + SecretRef</td><td><a href="./security.html">Security</a></td></tr></tbody></table><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./installation.html">Installation</a> — deploying the operator</li><li><a href="./performance.html">Performance</a> — scaling and optimization</li><li><a href="./security.html">Security</a> — RBAC and credential management</li></ul>`,15)])])}const b=n(r,[["render",t]]);export{m as __pageData,b as default};
